function scanWorkspaceFiles(rootDir) {
    const files = [];
    const excludeDirs = new Set(['node_modules', '.git', '.openclaw', 'scripts', 'self-improving', 'conversation-backup']);

    function walk(dir, relative = '') {
        const entries = fs.readdirSync(dir, { withFileTypes: true });
        for (const entry of entries) {
            if (excludeDirs.has(entry.name)) continue;

            const fullPath = path.join(dir, entry.name);
            const relPath = path.join(relative, entry.name);

            if (entry.isDirectory()) {
                walk(fullPath, relPath);
            } else {
                try {
                    const stats = fs.statSync(fullPath);
                    // 确定文件类型
                    const ext = path.extname(entry.name).toLowerCase();
                    let fileType = '其他';
                    if (ext === '.js' || ext === '.ts' || ext === '.py' || ext === '.ps1' || ext === '.sh') fileType = '脚本';
                    else if (ext === '.md') fileType = '文档';
                    else if (ext === '.json') fileType = '配置';
                    else if (ext === '.log') fileType = '日志';
                    else if (ext === '.txt') fileType = '文本';

                    files.push({
                        name: entry.name,
                        type: fileType,
                        path: relPath,
                        size: stats.size,
                        hash: computeHash(fullPath),
                        mtime: stats.mtime.toISOString()
                    });
                } catch (e) {
                    // 忽略无法访问的文件
                }
            }
        }
    }

    walk(rootDir);
    return files;
}

