// 查找文档
async function findDoc(token, title) {
    return new Promise((resolve, reject) => {
        const query = encodeURIComponent(title);
        const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: `/open-apis/docx/v1/documents?query=${query}`,
            method: 'GET',
            headers: {
                'Authorization': `Bearer ${token}`
            }
        };

        const req = https.request(options, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', async () => {
                try {
                    console.log(`[DEBUG] findDoc response status: ${res.statusCode}`);
                    console.log(`[DEBUG] findDoc response body: ${data.substring(0, 500)}`);
                    const result = JSON.parse(data);
                    if (result.code === 0 && result.data && result.data.documents && result.data.documents.length > 0) {
                        resolve(result.data.documents[0]);
                    } else {
                        resolve(null); // 未找到
                    }
                } catch (e) {
                    reject(new Error(`Find doc parse error: ${e.message}, raw: ${data.substring(0, 200)}`));
                }
            });
        });

        req.on('error', reject);
        req.end();
    });
}

